To proxy requests in an ASP.NET Core API, you can use the `HttpClient` class to make a request to the target endpoint and then return the response from the target endpoint to the client. Here's a basic example of how to do this:

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet]
    public async Task<IActionResult> Get(string path)
    {
        var request = new HttpRequestMessage(HttpMethod.Get, path);
        var response = await _httpClient.SendAsync(request);

        if (response.IsSuccessStatusCode)
        {
            return new ContentResult
            {
                Content = await response.Content.ReadAsStringAsync(),
                ContentType = response.Content.Headers.ContentType.MediaType
            };
        }
        else
        {
            return new StatusCodeResult((int)response.StatusCode);
        }
    }
}
```

